23	const getCachedRegistryItem = React.cache(
24	  async (name: string, styleName: Style["name"]) => {
25	    // Try registry item first, then fallback to demo item (for examples).
26	    const item = await getRegistryItem(name, styleName)
27	    if (item) {
28	      return item
29	    }
30	    return await getDemoItem(name, styleName)
31	  }
32	)
