34	export async function generateMetadata({
35	  params,
36	}: {
37	  params: Promise<{
38	    style: string
39	    name: string
40	  }>
41	}): Promise<Metadata> {
42	  const { style: styleName, name } = await params
43	  const style = getStyle(styleName)
44	
45	  if (!style) {
46	    return {}
47	  }
48	
49	  const item = await getCachedRegistryItem(name, style.name)
50	
51	  if (!item) {
52	    return {}
53	  }
54	
55	  const title = item.name
56	  const description = item.description
57	
58	  return {
59	    title: item.name,
60	    description,
61	    openGraph: {
62	      title,
63	      description,
64	      type: "article",
65	      url: absoluteUrl(`/view/${style.name}/${item.name}`),
66	      images: [
67	        {
68	          url: siteConfig.ogImage,
69	          width: 1200,
70	          height: 630,
71	          alt: siteConfig.name,
72	        },
