13	// LRU cache for cross-request caching of registry items.
14	// File reads are I/O-bound, so caching improves dev server performance.
15	// eslint-disable-next-line @typescript-eslint/no-explicit-any
16	const registryCache = new LRUCache<string, any>({
17	  max: 500,
18	  ttl: 1000 * 60 * 5, // 5 minutes (shorter for dev to pick up changes).
19	})
20	
21	function getBaseForStyle(styleName: string) {
22	  for (const base of BASES) {
23	    if (styleName.startsWith(`${base.name}-`)) {
24	      return base.name
25	    }
26	  }
27	  return null
28	}
29	
30	function getDemoIndexKey(styleName: string) {
31	  if (ExamplesIndex[styleName]) {
32	    return styleName
33	  }
34	
35	  const base = getBaseForStyle(styleName)
36	  if (base && ExamplesIndex[base]) {
37	    return base
38	  }
39	
40	  return styleName
41	}
42	
43	function getBaseIndex(styleName: string) {
44	  const base = getBaseForStyle(styleName)
45	  return base ? BasesIndex[base] : null
46	}
47	
48	function getStyleIndex(styleName: string) {
49	  return StylesIndex[styleName] ?? null
50	}
51	
52	function getMergedIndexForStyle(styleName: string) {
53	  const styleIndex = getStyleIndex(styleName)
54	  const baseIndex = getBaseIndex(styleName)
55	
56	  if (styleIndex && baseIndex) {
57	    return { ...baseIndex, ...styleIndex }
58	  }
59	
60	  return styleIndex ?? baseIndex
61	}
62	
63	function getRegistryEntry(name: string, styleName: string) {
64	  return getStyleIndex(styleName)?.[name] ?? getBaseIndex(styleName)?.[name]
65	}
66	
67	export function getDemoComponent(name: string, styleName: string) {
68	  const key = getDemoIndexKey(styleName)
69	  return ExamplesIndex[key]?.[name]?.component
70	}
71	
72	export async function getDemoItem(name: string, styleName: string) {
73	  const key = getDemoIndexKey(styleName)
74	  const demo = ExamplesIndex[key]?.[name]
75	  if (!demo) {
76	    return null
77	  }
78	
79	  const content = await readFileFromRoot(demo.filePath)
80	
81	  return {
82	    name: demo.name,
83	    type: "registry:internal" as const,
84	    files: [
85	      {
86	        path: demo.filePath,
87	        content,
88	        type: "registry:internal" as const,
89	      },
90	    ],
91	  }
92	}
93	
94	export function getRegistryComponent(name: string, styleName: string) {
95	  const demoComponent = getDemoComponent(name, styleName)
96	  if (demoComponent) {
97	    return demoComponent
98	  }
99	
100	  return getRegistryEntry(name, styleName)?.component
101	}
102	
103	export async function getRegistryItems(
104	  styleName: string,
105	  filter?: (item: z.infer<typeof registryItemSchema>) => boolean
106	) {
107	  const styleIndex = getMergedIndexForStyle(styleName)
108	
109	  if (!styleIndex) {
110	    return []
111	  }
112	
113	  const entries = Object.values(styleIndex)
114	
115	  const filteredEntries = filter ? entries.filter(filter) : entries
116	
117	  return await Promise.all(
118	    filteredEntries.map(async (entry) => {
119	      const item = await getRegistryItem(entry.name, styleName)
120	      return item
121	    })
122	  ).then((results) => results.filter(Boolean))
123	}
124	
125	export async function getRegistryItem(name: string, styleName: string) {
126	  const cacheKey = `${styleName}:${name}`
127	
128	  // Check cache first.
129	  if (registryCache.has(cacheKey)) {
130	    return registryCache.get(cacheKey)
131	  }
132	
133	  const item = getRegistryEntry(name, styleName)
134	
135	  if (!item) {
136	    registryCache.set(cacheKey, null)
137	    return null
138	  }
139	
140	  const normalizedItem = {
141	    ...item,
142	    files: item.files.map((file: unknown) =>
143	      typeof file === "string" ? { path: file } : file
144	    ),
145	  }
146	
147	  // Convert all file paths to object.
148	  // TODO: remove when we migrate to new registry.
149	  // Fail early before doing expensive file operations.
150	  const result = registryItemSchema.safeParse(normalizedItem)
151	  if (!result.success) {
152	    registryCache.set(cacheKey, null)
153	    return null
154	  }
155	
156	  // Read all files in parallel.
157	  let files: typeof result.data.files = await Promise.all(
158	    item.files.map(async (file: z.infer<typeof registryItemFileSchema>) => {
159	      const content = await getFileContent(file)
160	      const relativePath = path.relative(process.cwd(), file.path)
161	
162	      return {
163	        ...file,
164	        path: relativePath,
165	        content,
166	      }
167	    })
168	  )
169	
170	  // Fix file paths.
171	  files = fixFilePaths(files)
172	
173	  const parsed = registryItemSchema.safeParse({
174	    ...result.data,
175	    files,
176	  })
177	
178	  if (!parsed.success) {
179	    console.error(parsed.error.message)
180	    registryCache.set(cacheKey, null)
181	    return null
182	  }
183	
184	  // Cache the result.
185	  registryCache.set(cacheKey, parsed.data)
186	
187	  return parsed.data
188	}
189	
190	async function getFileContent(file: z.infer<typeof registryItemFileSchema>) {
191	  let code = await fs.readFile(file.path, "utf-8")
192	
193	  // Some registry items uses default export.
194	  // We want to use named export instead.
195	  if (file.type !== "registry:page") {
196	    code = code.replaceAll("export default", "export")
197	  }
198	
199	  // Fix imports.
200	  code = fixImport(code)
201	
202	  return code
203	}
204	
205	function getFileTarget(file: z.infer<typeof registryItemFileSchema>) {
206	  let target = file.target
207	
208	  if (!target || target === "") {
209	    const fileName = file.path.split("/").pop()
210	    if (
211	      file.type === "registry:block" ||
212	      file.type === "registry:component" ||
213	      file.type === "registry:example"
214	    ) {
215	      target = `components/${fileName}`
216	    }
217	
218	    if (file.type === "registry:ui") {
219	      target = `components/ui/${fileName}`
220	    }
221	
222	    if (file.type === "registry:hook") {
223	      target = `hooks/${fileName}`
224	    }
225	
226	    if (file.type === "registry:lib") {
227	      target = `lib/${fileName}`
228	    }
229	  }
230	
231	  return target ?? ""
232	}
233	
234	function fixFilePaths(files: z.infer<typeof registryItemSchema>["files"]) {
235	  if (!files) {
236	    return []
237	  }
238	
239	  // Resolve all paths relative to the first file's directory.
240	  const firstFilePath = files[0].path
241	  const firstFilePathDir = path.dirname(firstFilePath)
242	
243	  return files.map((file) => {
244	    return {
245	      ...file,
246	      path: path.relative(firstFilePathDir, file.path),
247	      target: getFileTarget(file),
248	    }
249	  })
250	}
251	
252	export function fixImport(content: string) {
253	  content = content.replace(
254	    /@\/styles\/([\w-]+)\/(ui-rtl|ui)\/([\w-]+)/g,
255	    (match, _styleName, type, component) => {
256	      if (type === "ui" || type === "ui-rtl") {
257	        return `@/components/ui/${component}`
258	      }
259	
260	      return match
261	    }
262	  )
263	
264	  const regex = /@\/(.+?)\/((?:.*?\/)?(?:components|ui|hooks|lib))\/([\w-]+)/g
265	
266	  const replacement = (
267	    match: string,
268	    path: string,
269	    type: string,
270	    component: string
271	  ) => {
272	    if (type.endsWith("components")) {
273	      return `@/components/${component}`
274	    } else if (type.endsWith("ui")) {
275	      return `@/components/ui/${component}`
276	    } else if (type.endsWith("hooks")) {
277	      return `@/hooks/${component}`
278	    } else if (type.endsWith("lib")) {
279	      return `@/lib/${component}`
280	    }
281	
282	    return match
283	  }
284	
285	  return content.replace(regex, replacement)
286	}
