288	export type FileTree = {
289	  name: string
290	  path?: string
291	  children?: FileTree[]
292	}
293	
294	export function createFileTreeForRegistryItemFiles(
295	  files: Array<{ path: string; target?: string }>
296	) {
297	  const root: FileTree[] = []
298	
299	  for (const file of files) {
300	    const path = file.target ?? file.path
301	    const parts = path.split("/")
302	    let currentLevel = root
303	
304	    for (let i = 0; i < parts.length; i++) {
305	      const part = parts[i]
306	      const isFile = i === parts.length - 1
307	      const existingNode = currentLevel.find((node) => node.name === part)
308	
309	      if (existingNode) {
310	        if (isFile) {
311	          // Update existing file node with full path
312	          existingNode.path = path
313	        } else {
314	          // Move to next level in the tree
315	          currentLevel = existingNode.children!
316	        }
317	      } else {
318	        const newNode: FileTree = isFile
319	          ? { name: part, path }
320	          : { name: part, children: [] }
321	
322	        currentLevel.push(newNode)
323	
324	        if (!isFile) {
325	          currentLevel = newNode.children!
326	        }
327	      }
328	    }
329	  }
330	
331	  return root
332	}
