- CSS variables: `origin-(--transform-origin)`, `max-h-(--available-height)`, `w-(--anchor-width)`
- Slide animations based on `data-[side=*]` attribute

---

### 11. INPUT WRAPPER PATTERNS

#### **InputGroup** (Addon Pattern with CVA)

```typescript
const inputGroupAddonVariants = cva(
  "flex h-auto cursor-text items-center justify-center gap-2 py-1.5",
  {
    variants: {
      align: {
        "inline-start": "order-first pl-2 has-[>button]:-ml-1",
        "inline-end": "order-last pr-2 has-[>button]:-mr-1",
        "block-start": "order-first w-full justify-start px-2.5 pt-2",
        "block-end": "order-last w-full justify-start px-2.5 pb-2",
      },
    },
  }
)

function InputGroupAddon({
  className,
  align = "inline-start",
  ...props
}: React.ComponentProps<"div"> & VariantProps<typeof inputGroupAddonVariants>) {
  return (
    <div
      role="group"
      data-slot="input-group-addon"
      data-align={align}
      className={cn(inputGroupAddonVariants({ align }), className)}
      onClick={(e) => {
        if ((e.target as HTMLElement).closest("button")) return
        e.currentTarget.parentElement?.querySelector("input")?.focus()
      }}
      {...props}
    />
  )
}

function InputGroupInput({ className, ...props }: React.ComponentProps<"input">) {
  return (
    <Input
      data-slot="input-group-control"
      className={cn(
        "flex-1 rounded-none border-0 bg-transparent shadow-none ring-0",
        className
      )}
      {...props}
    />
  )
}
```

