"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  onStepChange: (step: number) => void
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextProps = {
  step: number
  state: "active" | "completed" | "inactive"
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"nav"> & {
  activeStep: number
  onStepChange: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation, onStepChange }}>
      <nav
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex data-[orientation=horizontal]:flex-col data-[orientation=vertical]:flex-col",
          className
        )}
        aria-label="Progress"
        {...props}
      >
        {children}
      </nav>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep } = useStepper()

  const state =
    step === activeStep
      ? "active"
      : step < activeStep
        ? "completed"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex items-center group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=vertical]/stepper:flex-col group-data-[orientation=vertical]/stepper:items-stretch group-data-[orientation=vertical]/stepper:gap-1",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step, state, disabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      disabled={disabled}
      className={cn(
        "inline-flex items-center gap-3 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:text-foreground data-[state=completed]:text-foreground data-[state=inactive]:text-muted-foreground",
        className
      )}
      onClick={() => onStepChange(step)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium transition-colors",
        "data-[state=active]:text-foreground data-[state=completed]:text-foreground data-[state=inactive]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs text-muted-foreground transition-colors",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation, activeStep } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="separator"
      className={cn(
        "shrink-0 bg-border transition-colors data-[state=completed]:bg-foreground",
        "data-[orientation=horizontal]:h-px data-[orientation=horizontal]:w-full data-[orientation=horizontal]:flex-1",
        "data-[orientation=vertical]:ml-5 data-[orientation=vertical]:h-8 data-[orientation=vertical]:w-px",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      data-state="active"
      className={cn("mt-4", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

